import { CommonModule } from '@angular/common';
import { Component, signal } from '@angular/core';

interface AccordionItem {
  id: string;
  title: string;
  content: string;
}

@Component({
  selector: 'app-accordion',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './accordion.html',
  styleUrl: './accordion.scss',
})
export class Accordion {
  readonly items: AccordionItem[] = [
    {
      id: 'keyboard-navigation',
      title: 'Keyboard Navigation',
      content:
        'Accordion headers are native buttons, so users can Tab to each header and activate it with Enter or Space.',
    },
    {
      id: 'aria-state',
      title: 'ARIA State',
      content:
        'Each accordion trigger exposes aria-expanded and aria-controls so assistive technology can understand the current state.',
    },
    {
      id: 'content-structure',
      title: 'Content Structure',
      content:
        'Each expanded panel is associated with its trigger through aria-labelledby, which helps preserve structure and relationships.',
    },
  ];

  openIndexes = signal<number[]>([0]);

  toggleItem(index: number): void {
    const current = this.openIndexes();

    if (current.includes(index)) {
      this.openIndexes.set(current.filter((itemIndex) => itemIndex !== index));
      return;
    }

    this.openIndexes.set([...current, index]);
  }

  isOpen(index: number): boolean {
    return this.openIndexes().includes(index);
  }

  getHeaderId(index: number): string {
    return `accordion-header-${this.items[index].id}`;
  }

  getPanelId(index: number): string {
    return `accordion-panel-${this.items[index].id}`;
  }
}

import { CommonModule } from '@angular/common';
import { Component, HostListener, computed, signal } from '@angular/core';

interface CalendarDay {
  date: Date;
  dayNumber: number;
  isCurrentMonth: boolean;
  isToday: boolean;
  isSelected: boolean;
  isFocused: boolean;
}

@Component({
  selector: 'app-date-picker',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './date-picker.html',
  styleUrl: './date-picker.scss',
})
export class DatePicker {
  readonly weekdayLabels = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];

  readonly isOpen = signal(false);
  readonly visibleMonth = signal(this.startOfMonth(new Date()));
  readonly selectedDate = signal<Date | null>(null);
  readonly focusedDate = signal(this.stripTime(new Date()));

  readonly monthLabel = computed(() => {
    return this.visibleMonth().toLocaleDateString('en-US', {
      month: 'long',
      year: 'numeric',
    });
  });

  readonly calendarDays = computed(() => {
    const monthStart = this.visibleMonth();
    const startDate = new Date(monthStart);
    startDate.setDate(startDate.getDate() - monthStart.getDay());

    const selected = this.selectedDate();
    const focused = this.focusedDate();
    const today = this.stripTime(new Date());

    const days: CalendarDay[] = [];

    for (let index = 0; index < 42; index += 1) {
      const current = new Date(startDate);
      current.setDate(startDate.getDate() + index);

      days.push({
        date: current,
        dayNumber: current.getDate(),
        isCurrentMonth: current.getMonth() === monthStart.getMonth(),
        isToday: this.isSameDate(current, today),
        isSelected: selected ? this.isSameDate(current, selected) : false,
        isFocused: this.isSameDate(current, focused),
      });
    }

    return days;
  });

  get selectedDateLabel(): string {
    const value = this.selectedDate();

    if (!value) {
      return 'Select a date';
    }

    return value.toLocaleDateString('en-US', {
      year: 'numeric',
      month: 'long',
      day: 'numeric',
    });
  }

  toggleCalendar(): void {
    const next = !this.isOpen();
    this.isOpen.set(next);

    if (next) {
      const baseDate = this.selectedDate() ?? new Date();
      const normalized = this.stripTime(baseDate);
      this.focusedDate.set(normalized);
      this.visibleMonth.set(this.startOfMonth(normalized));
    }
  }

  closeCalendar(): void {
    this.isOpen.set(false);
  }

  selectDate(date: Date): void {
    const normalized = this.stripTime(date);
    this.selectedDate.set(normalized);
    this.focusedDate.set(normalized);
    this.visibleMonth.set(this.startOfMonth(normalized));
    this.closeCalendar();
  }

  selectToday(): void {
    const today = this.stripTime(new Date());
    this.selectDate(today);
  }

  previousMonth(): void {
    const previous = new Date(this.visibleMonth());
    previous.setMonth(previous.getMonth() - 1);
    this.visibleMonth.set(this.startOfMonth(previous));
    this.syncFocusedMonth();
  }

  nextMonth(): void {
    const next = new Date(this.visibleMonth());
    next.setMonth(next.getMonth() + 1);
    this.visibleMonth.set(this.startOfMonth(next));
    this.syncFocusedMonth();
  }

  onDayKeydown(event: KeyboardEvent): void {
    switch (event.key) {
      case 'ArrowLeft':
        event.preventDefault();
        this.moveFocusedDate(-1);
        break;
      case 'ArrowRight':
        event.preventDefault();
        this.moveFocusedDate(1);
        break;
      case 'ArrowUp':
        event.preventDefault();
        this.moveFocusedDate(-7);
        break;
      case 'ArrowDown':
        event.preventDefault();
        this.moveFocusedDate(7);
        break;
      case 'Home':
        event.preventDefault();
        this.moveToStartOfWeek();
        break;
      case 'End':
        event.preventDefault();
        this.moveToEndOfWeek();
        break;
      case 'PageUp':
        event.preventDefault();
        this.moveFocusedMonth(-1);
        break;
      case 'PageDown':
        event.preventDefault();
        this.moveFocusedMonth(1);
        break;
      case 'Enter':
      case ' ':
        event.preventDefault();
        this.selectDate(this.focusedDate());
        break;
      case 'Escape':
        event.preventDefault();
        this.closeCalendar();
        break;
    }
  }

  setFocusedDate(date: Date): void {
    const normalized = this.stripTime(date);
    this.focusedDate.set(normalized);

    if (
      normalized.getMonth() !== this.visibleMonth().getMonth() ||
      normalized.getFullYear() !== this.visibleMonth().getFullYear()
    ) {
      this.visibleMonth.set(this.startOfMonth(normalized));
    }
  }

  isSameDate(first: Date, second: Date): boolean {
    return (
      first.getFullYear() === second.getFullYear()
      && first.getMonth() === second.getMonth()
      && first.getDate() === second.getDate()
    );
  }

  formatAriaLabel(date: Date): string {
    return date.toLocaleDateString('en-US', {
      weekday: 'long',
      year: 'numeric',
      month: 'long',
      day: 'numeric',
    });
  }

  trackByDate(_: number, day: CalendarDay): string {
    return day.date.toISOString();
  }

  @HostListener('document:keydown', ['$event'])
  onDocumentKeydown(event: KeyboardEvent): void {
    if (!this.isOpen()) {
      return;
    }

    if (event.key === 'Escape') {
      event.preventDefault();
      this.closeCalendar();
    }
  }

  @HostListener('document:click', ['$event'])
  onDocumentClick(event: MouseEvent): void {
    const target = event.target as HTMLElement | null;

    if (!target?.closest('.date-picker')) {
      this.closeCalendar();
    }
  }

  private moveFocusedDate(days: number): void {
    const next = new Date(this.focusedDate());
    next.setDate(next.getDate() + days);
    this.setFocusedDate(next);
  }

  private moveFocusedMonth(months: number): void {
    const next = new Date(this.focusedDate());
    next.setMonth(next.getMonth() + months);
    this.setFocusedDate(next);
  }

  private moveToStartOfWeek(): void {
    const next = new Date(this.focusedDate());
    next.setDate(next.getDate() - next.getDay());
    this.setFocusedDate(next);
  }

  private moveToEndOfWeek(): void {
    const next = new Date(this.focusedDate());
    next.setDate(next.getDate() + (6 - next.getDay()));
    this.setFocusedDate(next);
  }

  private syncFocusedMonth(): void {
    const focused = this.focusedDate();
    const visible = this.visibleMonth();

    if (
      focused.getMonth() !== visible.getMonth()
      || focused.getFullYear() !== visible.getFullYear()
    ) {
      const next = new Date(visible);
      const maxDay = new Date(
        visible.getFullYear(),
        visible.getMonth() + 1,
        0,
      ).getDate();

      next.setDate(Math.min(focused.getDate(), maxDay));
      this.focusedDate.set(this.stripTime(next));
    }
  }

  private startOfMonth(date: Date): Date {
    return new Date(date.getFullYear(), date.getMonth(), 1);
  }

  private stripTime(date: Date): Date {
    return new Date(date.getFullYear(), date.getMonth(), date.getDate());
  }
}

import { CommonModule } from '@angular/common';
import { Component, computed, signal } from '@angular/core';

type SortDirection = 'asc' | 'desc';

interface DataTableRow {
  id: number;
  name: string;
  role: string;
  team: string;
  status: string;
}

type SortColumn = 'name' | 'role' | 'team' | 'status';

@Component({
  selector: 'app-data-table',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './data-table.html',
  styleUrl: './data-table.scss',
})
export class DataTable {
  readonly pageSize = 5;

  readonly rows = signal<DataTableRow[]>([
    { id: 1, name: 'Ana López', role: 'Frontend Developer', team: 'Platform', status: 'Active' },
    { id: 2, name: 'Marco Ruiz', role: 'QA Engineer', team: 'Accessibility', status: 'Active' },
    { id: 3, name: 'Sofía Torres', role: 'Project Manager', team: 'Delivery', status: 'On Leave' },
    { id: 4, name: 'Luis Mendoza', role: 'Backend Developer', team: 'Platform', status: 'Active' },
    { id: 5, name: 'Elena Castro', role: 'UX Designer', team: 'Design', status: 'Active' },
    { id: 6, name: 'Jorge Silva', role: 'DevOps Engineer', team: 'Infrastructure', status: 'Inactive' },
    { id: 7, name: 'Camila Vega', role: 'Business Analyst', team: 'Delivery', status: 'Active' },
    { id: 8, name: 'Diego Herrera', role: 'Frontend Developer', team: 'Accessibility', status: 'Active' },
    { id: 9, name: 'Valeria Gómez', role: 'QA Engineer', team: 'Platform', status: 'Active' },
    { id: 10, name: 'Ricardo Díaz', role: 'Product Owner', team: 'Delivery', status: 'Active' },
    { id: 11, name: 'Fernanda Pérez', role: 'UI Developer', team: 'Design', status: 'Inactive' },
    { id: 12, name: 'Gabriel Navarro', role: 'Scrum Master', team: 'Delivery', status: 'Active' },
  ]);

  readonly currentPage = signal(1);
  readonly sortColumn = signal<SortColumn>('name');
  readonly sortDirection = signal<SortDirection>('asc');

  readonly totalPages = computed(() => {
    return Math.ceil(this.rows().length / this.pageSize);
  });

  readonly sortedRows = computed(() => {
    const column = this.sortColumn();
    const direction = this.sortDirection();
    const sorted = [...this.rows()].sort((a, b) => {
      const valueA = a[column].toLowerCase();
      const valueB = b[column].toLowerCase();

      if (valueA < valueB) {
        return direction === 'asc' ? -1 : 1;
      }

      if (valueA > valueB) {
        return direction === 'asc' ? 1 : -1;
      }

      return 0;
    });

    return sorted;
  });

  readonly paginatedRows = computed(() => {
    const start = (this.currentPage() - 1) * this.pageSize;
    const end = start + this.pageSize;

    return this.sortedRows().slice(start, end);
  });

  readonly pageStart = computed(() => {
    return (this.currentPage() - 1) * this.pageSize + 1;
  });

  readonly pageEnd = computed(() => {
    return Math.min(this.currentPage() * this.pageSize, this.rows().length);
  });

  sortBy(column: SortColumn): void {
    if (this.sortColumn() === column) {
      this.sortDirection.set(this.sortDirection() === 'asc' ? 'desc' : 'asc');
    } else {
      this.sortColumn.set(column);
      this.sortDirection.set('asc');
    }

    this.currentPage.set(1);
  }

  previousPage(): void {
    if (this.currentPage() > 1) {
      this.currentPage.update((page) => page - 1);
    }
  }

  nextPage(): void {
    if (this.currentPage() < this.totalPages()) {
      this.currentPage.update((page) => page + 1);
    }
  }

  getAriaSort(column: SortColumn): 'ascending' | 'descending' | 'none' {
    if (this.sortColumn() !== column) {
      return 'none';
    }

    return this.sortDirection() === 'asc' ? 'ascending' : 'descending';
  }

  getSortLabel(column: SortColumn, label: string): string {
    if (this.sortColumn() !== column) {
      return `Sort by ${label}`;
    }

    const nextDirection = this.sortDirection() === 'asc' ? 'descending' : 'ascending';
    return `Sort by ${label}, currently ${this.sortDirection() === 'asc' ? 'ascending' : 'descending'}, activate to sort ${nextDirection}`;
  }

  getSortIndicator(column: SortColumn): string {
    if (this.sortColumn() !== column) {
      return '↕';
    }

    return this.sortDirection() === 'asc' ? '↑' : '↓';
  }
}

import { CommonModule } from '@angular/common';
import { Component, ElementRef, HostListener, ViewChild, signal } from '@angular/core';

interface DropdownOption {
  id: string;
  label: string;
}

@Component({
  selector: 'app-dropdown-menu',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './dropdown-menu.html',
  styleUrl: './dropdown-menu.scss',
})
export class DropdownMenu {
  @ViewChild('singleMenuButton') singleMenuButton?: ElementRef<HTMLButtonElement>;
  @ViewChild('multiMenuButton') multiMenuButton?: ElementRef<HTMLButtonElement>;

  readonly singleOptions: DropdownOption[] = [
    { id: 'angular', label: 'Angular' },
    { id: 'react', label: 'React' },
    { id: 'vue', label: 'Vue' },
    { id: 'svelte', label: 'Svelte' },
  ];

  readonly multiOptions: DropdownOption[] = [
    { id: 'keyboard', label: 'Keyboard Support' },
    { id: 'screen-reader', label: 'Screen Reader Support' },
    { id: 'focus', label: 'Focus Management' },
    { id: 'contrast', label: 'Color Contrast' },
  ];

  singleOpen = signal(false);
  multiOpen = signal(false);

  activeSingleIndex = signal(0);
  activeMultiIndex = signal(0);

  selectedSingle = signal<string>('');
  selectedMulti = signal<string[]>([]);

  get selectedSingleLabel(): string {
    const found = this.singleOptions.find((option) => option.id === this.selectedSingle());
    return found?.label ?? 'Select a framework';
  }

  get selectedMultiLabel(): string {
    if (this.selectedMulti().length === 0) {
      return 'Select accessibility topics';
    }

    return this.multiOptions
      .filter((option) => this.selectedMulti().includes(option.id))
      .map((option) => option.label)
      .join(', ');
  }

  toggleSingleMenu(): void {
    const next = !this.singleOpen();
    this.singleOpen.set(next);
    this.multiOpen.set(false);

    if (next) {
      const selectedIndex = this.singleOptions.findIndex(
        (option) => option.id === this.selectedSingle(),
      );
      this.activeSingleIndex.set(selectedIndex >= 0 ? selectedIndex : 0);
    }
  }

  toggleMultiMenu(): void {
    const next = !this.multiOpen();
    this.multiOpen.set(next);
    this.singleOpen.set(false);

    if (next) {
      this.activeMultiIndex.set(0);
    }
  }

  closeSingleMenu(): void {
    this.singleOpen.set(false);
  }

  closeMultiMenu(): void {
    this.multiOpen.set(false);
  }

  selectSingle(optionId: string): void {
    this.selectedSingle.set(optionId);
    this.closeSingleMenu();
    this.singleMenuButton?.nativeElement.focus();
  }

  toggleMultiSelection(optionId: string): void {
    const current = this.selectedMulti();

    if (current.includes(optionId)) {
      this.selectedMulti.set(current.filter((id) => id !== optionId));
      return;
    }

    this.selectedMulti.set([...current, optionId]);
  }

  isMultiSelected(optionId: string): boolean {
    return this.selectedMulti().includes(optionId);
  }

  onSingleButtonKeydown(event: KeyboardEvent): void {
    switch (event.key) {
      case 'ArrowDown':
      case 'Enter':
      case ' ': {
        event.preventDefault();
        if (!this.singleOpen()) {
          this.toggleSingleMenu();
        }
        break;
      }
      case 'Escape': {
        event.preventDefault();
        this.closeSingleMenu();
        break;
      }
    }
  }

  onMultiButtonKeydown(event: KeyboardEvent): void {
    switch (event.key) {
      case 'ArrowDown':
      case 'Enter':
      case ' ': {
        event.preventDefault();
        if (!this.multiOpen()) {
          this.toggleMultiMenu();
        }
        break;
      }
      case 'Escape': {
        event.preventDefault();
        this.closeMultiMenu();
        break;
      }
    }
  }

  onSingleOptionKeydown(event: KeyboardEvent): void {
    switch (event.key) {
      case 'ArrowDown': {
        event.preventDefault();
        this.activeSingleIndex.set(
          this.activeSingleIndex() < this.singleOptions.length - 1
            ? this.activeSingleIndex() + 1
            : 0,
        );
        break;
      }
      case 'ArrowUp': {
        event.preventDefault();
        this.activeSingleIndex.set(
          this.activeSingleIndex() > 0
            ? this.activeSingleIndex() - 1
            : this.singleOptions.length - 1,
        );
        break;
      }
      case 'Home': {
        event.preventDefault();
        this.activeSingleIndex.set(0);
        break;
      }
      case 'End': {
        event.preventDefault();
        this.activeSingleIndex.set(this.singleOptions.length - 1);
        break;
      }
      case 'Enter':
      case ' ': {
        event.preventDefault();
        const option = this.singleOptions[this.activeSingleIndex()];
        this.selectSingle(option.id);
        break;
      }
      case 'Escape': {
        event.preventDefault();
        this.closeSingleMenu();
        this.singleMenuButton?.nativeElement.focus();
        break;
      }
      case 'Tab': {
        this.closeSingleMenu();
        break;
      }
    }
  }

  onMultiOptionKeydown(event: KeyboardEvent): void {
    switch (event.key) {
      case 'ArrowDown': {
        event.preventDefault();
        this.activeMultiIndex.set(
          this.activeMultiIndex() < this.multiOptions.length - 1
            ? this.activeMultiIndex() + 1
            : 0,
        );
        break;
      }
      case 'ArrowUp': {
        event.preventDefault();
        this.activeMultiIndex.set(
          this.activeMultiIndex() > 0
            ? this.activeMultiIndex() - 1
            : this.multiOptions.length - 1,
        );
        break;
      }
      case 'Home': {
        event.preventDefault();
        this.activeMultiIndex.set(0);
        break;
      }
      case 'End': {
        event.preventDefault();
        this.activeMultiIndex.set(this.multiOptions.length - 1);
        break;
      }
      case 'Enter':
      case ' ': {
        event.preventDefault();
        const option = this.multiOptions[this.activeMultiIndex()];
        this.toggleMultiSelection(option.id);
        break;
      }
      case 'Escape': {
        event.preventDefault();
        this.closeMultiMenu();
        this.multiMenuButton?.nativeElement.focus();
        break;
      }
      case 'Tab': {
        this.closeMultiMenu();
        break;
      }
    }
  }

  @HostListener('document:click', ['$event'])
  onDocumentClick(event: MouseEvent): void {
    const target = event.target as HTMLElement | null;

    if (!target?.closest('.dropdown-menu')) {
      this.closeSingleMenu();
      this.closeMultiMenu();
    }
  }
}

import { CommonModule } from '@angular/common';
import { Component, HostListener, signal } from '@angular/core';

interface NavChildItem {
  label: string;
  href: string;
}

interface NavItem {
  label: string;
  href?: string;
  children?: NavChildItem[];
}

@Component({
  selector: 'app-navigation-bar',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './navigation-bar.html',
  styleUrl: './navigation-bar.scss',
})
export class NavigationBar {
  mobileMenuOpen = signal(false);
  componentsMenuOpen = signal(false);

  navItems: NavItem[] = [
    { label: 'Home', href: '#home' },
    {
      label: 'Components',
      children: [
        { label: 'Skip Navigation', href: '#skip-navigation' },
        { label: 'Navigation Bar', href: '#navigation-bar' },
        { label: 'Modal Dialog', href: '#modal-dialog' },
        { label: 'Form Inputs', href: '#form-inputs' },
        { label: 'Data Table', href: '#data-table' },
        { label: 'Dropdown Menu', href: '#dropdown-menu' },
        { label: 'Tabs', href: '#tabs' },
        { label: 'Accordion', href: '#accordion' },
        { label: 'Toast Alert', href: '#toast-alert' },
        { label: 'Date Picker', href: '#date-picker' },
      ],
    },
    { label: 'Documentation', href: '#documentation' },
    { label: 'Contact', href: '#contact' },
  ];

  toggleMobileMenu(): void {
    this.mobileMenuOpen.update((value) => !value);
  }

  closeMobileMenu(): void {
    this.mobileMenuOpen.set(false);
  }

  toggleProductsMenu(): void {
    this.componentsMenuOpen.update((value) => !value);
  }

  openProductsMenu(): void {
    this.componentsMenuOpen.set(true);
  }

  closeProductsMenu(): void {
    this.componentsMenuOpen.set(false);
  }

  onMenuButtonKeydown(event: KeyboardEvent): void {
    switch (event.key) {
      case 'ArrowDown':
      case 'Enter':
      case ' ':
        event.preventDefault();
        this.openProductsMenu();
        setTimeout(() => {
          const firstItem = document.querySelector<HTMLElement>(
            '#components-menu a'
          );
          firstItem?.focus();
        });
        break;
      case 'Escape':
        event.preventDefault();
        this.closeProductsMenu();
        break;
    }
  }

  onDropdownItemKeydown(event: KeyboardEvent): void {
    const items = Array.from(
      document.querySelectorAll<HTMLElement>('#components-menu a')
    );

    const currentIndex = items.findIndex((item) => item === document.activeElement);

    switch (event.key) {
      case 'ArrowDown': {
        event.preventDefault();
        const nextIndex = currentIndex < items.length - 1 ? currentIndex + 1 : 0;
        items[nextIndex]?.focus();
        break;
      }
      case 'ArrowUp': {
        event.preventDefault();
        const prevIndex = currentIndex > 0 ? currentIndex - 1 : items.length - 1;
        items[prevIndex]?.focus();
        break;
      }
      case 'Home':
        event.preventDefault();
        items[0]?.focus();
        break;
      case 'End':
        event.preventDefault();
        items[items.length - 1]?.focus();
        break;
      case 'Escape':
        event.preventDefault();
        this.closeProductsMenu();
        document.getElementById('components-menu-button')?.focus();
        break;
      case 'Tab':
        this.closeProductsMenu();
        break;
    }
  }

  @HostListener('document:click', ['$event'])
  onDocumentClick(event: MouseEvent): void {
    const target = event.target as HTMLElement | null;
    if (!target?.closest('.navigation-bar')) {
      this.closeProductsMenu();
    }
  }
}

import { CommonModule } from '@angular/common';
import { Component, HostListener, signal } from '@angular/core';

